// RAKITRAKATRA LIQUID - FIXED v1.0
(function(){
  var R = window.Rakitrakatra || {};
  if(typeof window.Rakitrakatra === 'undefined') window.Rakitrakatra = R;
  
  R.Liquid = function(kianja, opts){
    opts = opts || {};
    this.kianja = kianja;
    this.x = opts.x || 0;
    this.y = opts.y || 400;
    this.w = opts.sakany || 800;
    this.h = opts.haavony || 200;
    this.color = opts.loko || 'rgba(0,255,255,0.6)';
    this.particles = [];
    this.count = opts.particules || 80;
    this.waveOffset = 0;
    
    for(var i=0; i<this.count; i++){
      this.particles.push({
        x: this.x + Math.random() * this.w,
        y: this.y + Math.random() * this.h,
        vx: (Math.random()-0.5) * 30,
        vy: (Math.random()-0.5) * 20,
        r: 3 + Math.random() * 6
      });
    }
    
    if(kianja && kianja.zavatra) kianja.zavatra.push(this);
    console.log('✅ Liquid loaded with', this.count, 'particles');
  };
  
  R.Liquid.prototype.havaozy = function(dt){
    this.waveOffset += dt * 2;
    var self=this;
    this.particles.forEach(function(p){
      p.x += p.vx * dt;
      p.y += p.vy * dt;
      p.vy += Math.sin(self.waveOffset + p.x*0.01) * 10 * dt;
      
      if(p.x < self.x) p.x = self.x + self.w;
      if(p.x > self.x + self.w) p.x = self.x;
      if(p.y < self.y) { p.y = self.y; p.vy *= -0.5; }
      if(p.y > self.y + self.h) { p.y = self.y + self.h; p.vy *= -0.5; }
    });
  };
  
  R.Liquid.prototype.soraty = function(ctx){
    if(!ctx) return;
    ctx.save();
    
    // Water base
    ctx.fillStyle = this.color;
    ctx.beginPath();
    ctx.moveTo(this.x, this.y + this.h);
    for(var x=this.x; x<=this.x+this.w; x+=10){
      var waveY = this.y + Math.sin(x*0.02 + this.waveOffset) * 5;
      ctx.lineTo(x, waveY);
    }
    ctx.lineTo(this.x+this.w, this.y+this.h);
    ctx.closePath();
    ctx.fill();
    
    // Particles (metaball style)
    var self=this;
    this.particles.forEach(function(p){
      ctx.fillStyle = self.color;
      ctx.beginPath();
      ctx.arc(p.x, p.y, p.r, 0, Math.PI*2);
      ctx.fill();
    });
    
    ctx.restore();
  };
  
  console.log('✅ rakitrakatra.liquid.min.js FIXED');
})();
